 1	import React, { FC } from 'react';
 2	
 3	import { ConfigMapModel, modelToGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getName } from '@kubevirt-utils/resources/shared';
 6	import { Alert, AlertVariant, Button, ButtonVariant } from '@patternfly/react-core';
 7	
 8	import InlineFilterSelect from '../FilterSelect/InlineFilterSelect';
 9	import Loading from '../Loading/Loading';
10	
11	import useSysprepConfigMaps from './hooks/useConfigMaps';
12	
13	type SelectSysprepProps = {
14	  id?: string;
15	  namespace: string;
16	  onSelectSysprep: (secretName: string) => void;
17	  selectedSysprepName: string;
18	};
19	
20	const SelectSysprep: FC<SelectSysprepProps> = ({
21	  id,
22	  namespace,
23	  onSelectSysprep,
24	  selectedSysprepName,
25	}) => {
26	  const { t } = useKubevirtTranslation();
27	  const [sysprepConfigMaps, configmapsLoaded, configmapsError] = useSysprepConfigMaps(namespace);
28	
29	  if (configmapsError)
30	    return (
31	      <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
32	        {configmapsError?.message}
33	      </Alert>
34	    );
35	
36	  return (
37	    <>
38	      {configmapsLoaded ? (
39	        <InlineFilterSelect
40	          options={sysprepConfigMaps?.map((configMap) => {
41	            const name = getName(configMap);
42	            return {
43	              children: name,
44	              groupVersionKind: modelToGroupVersionKind(ConfigMapModel),
45	              value: name,
46	            };
47	          })}
48	          selected={selectedSysprepName}
49	          setSelected={onSelectSysprep}
50	          toggleProps={{ id, placeholder: t('--- Select sysprep ---') }}
51	        />
52	      ) : (
53	        <Loading />
54	      )}
55	      {selectedSysprepName && (
56	        <Button isDanger onClick={() => onSelectSysprep(undefined)} variant={ButtonVariant.link}>
57	          {t('Detach sysprep')}
58	        </Button>
59	      )}
60	    </>
61	  );
62	};
63	
64	export default SelectSysprep;

